import{_ as e,o as i,c as s,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Seguridad","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/apis-rest/06-seguridad.md","filePath":"full-stack/arquitectura/apis-rest/06-seguridad.md","lastUpdated":1782521464000}'),n={name:"full-stack/arquitectura/apis-rest/06-seguridad.md"};function l(t,a,r,d,c,u){return i(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h1><p>Una API REST expone capacidades del sistema. La seguridad no se anade al final: forma parte del contrato.</p><h2 id="autenticacion" tabindex="-1">Autenticacion <a class="header-anchor" href="#autenticacion" aria-label="Permalink to &quot;Autenticacion&quot;">​</a></h2><p>La API debe saber quien llama.</p><p>Opciones habituales:</p><ul><li>Cookies de sesion.</li><li>JWT.</li><li>OAuth 2.0 / OpenID Connect.</li><li>API keys para integraciones servidor a servidor.</li></ul><h2 id="autorizacion" tabindex="-1">Autorizacion <a class="header-anchor" href="#autorizacion" aria-label="Permalink to &quot;Autorizacion&quot;">​</a></h2><p>La autenticacion no basta. Tambien hay que validar que puede hacer la identidad.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usuario autenticado</span></span>
<span class="line"><span>  -&gt; puede leer sus pedidos</span></span>
<span class="line"><span>  -&gt; no puede leer pedidos de otro usuario</span></span>
<span class="line"><span>  -&gt; admin puede gestionar pedidos</span></span></code></pre></div><h2 id="validacion-de-entrada" tabindex="-1">Validacion de entrada <a class="header-anchor" href="#validacion-de-entrada" aria-label="Permalink to &quot;Validacion de entrada&quot;">​</a></h2><p>Valida tipos, longitudes, rangos, formatos, campos permitidos y reglas de negocio. No confies en validaciones del frontend.</p><h2 id="protecciones-basicas" tabindex="-1">Protecciones basicas <a class="header-anchor" href="#protecciones-basicas" aria-label="Permalink to &quot;Protecciones basicas&quot;">​</a></h2><ul><li>HTTPS obligatorio.</li><li>CORS configurado de forma explicita.</li><li>Rate limiting.</li><li>Limites de tamano de payload.</li><li>Sanitizacion de logs.</li><li>Proteccion contra mass assignment.</li><li>Gestion segura de secretos.</li></ul><h2 id="datos-sensibles" tabindex="-1">Datos sensibles <a class="header-anchor" href="#datos-sensibles" aria-label="Permalink to &quot;Datos sensibles&quot;">​</a></h2><p>No devuelvas:</p><ul><li>Password hashes.</li><li>Tokens.</li><li>Secretos.</li><li>Campos internos.</li><li>Datos personales innecesarios.</li></ul><h2 id="errores-de-seguridad-comunes" tabindex="-1">Errores de seguridad comunes <a class="header-anchor" href="#errores-de-seguridad-comunes" aria-label="Permalink to &quot;Errores de seguridad comunes&quot;">​</a></h2><ul><li><code>GET /users/{id}</code> sin comprobar propietario.</li><li>Permitir <code>role=admin</code> en payload de actualizacion.</li><li>Logs con tokens.</li><li>CORS abierto sin necesidad.</li><li>JWT sin expiracion ni rotacion.</li></ul><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Cada endpoint tiene politica de permisos.</li><li>Los tokens no se exponen en logs.</li><li>Los payloads tienen limite.</li><li>Los campos modificables estan controlados.</li><li>Los errores no revelan informacion sensible.</li></ul>`,20)])])}const m=e(n,[["render",l]]);export{h as __pageData,m as default};
